{
  "name": "Kazi Ledger",
  "description": "A mobile-first, AI-powered accounting application for small business owners. Record transactions using natural language, track debts, and visualize business health with a modern Bento-style dashboard."
}

export enum TransactionType {
  INCOME = 'INCOME',
  EXPENSE = 'EXPENSE',
  DEBT = 'DEBT',
  DEBT_PAYMENT = 'DEBT_PAYMENT'
}

export interface Transaction {
  id: string;
  user_id: string;
  type: TransactionType;
  amount: number;
  category: string;
  counterparty: string;
  description: string;
  date: string;
}

export interface Profile {
  id: string;
  business_name: string;
  currency: string;
}

export interface AIResponse {
  intent: 'RECORD' | 'QUERY' | 'UNKNOWN';
  transaction?: {
    type: TransactionType;
    amount: number;
    category: string;
    counterparty: string;
    description: string;
  };
  query_answer?: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { AIResponse, TransactionType } from "./types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

const responseSchema = {
  type: Type.OBJECT,
  properties: {
    intent: {
      type: Type.STRING,
      description: "RECORD for adding a transaction, QUERY for asking about history.",
    },
    transaction: {
      type: Type.OBJECT,
      properties: {
        type: { type: Type.STRING, description: "INCOME, EXPENSE, DEBT, or DEBT_PAYMENT" },
        amount: { type: Type.NUMBER },
        category: { type: Type.STRING },
        counterparty: { type: Type.STRING },
        description: { type: Type.STRING },
      },
    },
    query_answer: {
      type: Type.STRING,
      description: "The answer if the user is asking a question.",
    },
  },
  required: ["intent"],
};

export const parseNaturalLanguage = async (input: string, context: string): Promise<AIResponse> => {
  const prompt = `
    You are Kazi Ledger AI. Analyze this user input: "${input}".
    Context of existing ledger data summary: ${context}

    If it's a new record:
    - INCOME: "Sold 3 sodas for 5000" -> amount 5000, category "Sales", counterparty "Customer"
    - EXPENSE: "Paid 10000 for rent" -> amount 10000, category "Rent"
    - DEBT: "Gave John goods worth 2000 on credit" -> amount 2000, type DEBT, counterparty "John"
    - DEBT_PAYMENT: "John paid back 500" -> amount 500, type DEBT_PAYMENT, counterparty "John"

    If it's a query:
    - "How much did I make today?" -> answer based on context.

    Return the result in structured JSON.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
      },
    });

    return JSON.parse(response.text || "{}") as AIResponse;
  } catch (error) {
    console.error("AI Parsing Error:", error);
    throw error;
  }
};

import { Transaction, Profile, TransactionType } from "./types";

const STORAGE_KEY_TRANSACTIONS = "kazi_transactions";
const STORAGE_KEY_PROFILE = "kazi_profile";

export const db = {
  getTransactions: (): Transaction[] => {
    const data = localStorage.getItem(STORAGE_KEY_TRANSACTIONS);
    return data ? JSON.parse(data) : [];
  },

  saveTransaction: (transaction: Omit<Transaction, "id" | "user_id">): Transaction => {
    const transactions = db.getTransactions();
    const newTx: Transaction = {
      ...transaction,
      id: crypto.randomUUID(),
      user_id: "demo-user",
    };
    transactions.unshift(newTx);
    localStorage.setItem(STORAGE_KEY_TRANSACTIONS, JSON.stringify(transactions));
    return newTx;
  },

  getProfile: (): Profile => {
    const data = localStorage.getItem(STORAGE_KEY_PROFILE);
    return data ? JSON.parse(data) : { id: "1", business_name: "My Business", currency: "UGX" };
  },

  updateProfile: (profile: Profile) => {
    localStorage.setItem(STORAGE_KEY_PROFILE, JSON.stringify(profile));
  },

  getStats: () => {
    const txs = db.getTransactions();
    const today = new Date().toISOString().split("T")[0];

    const todayTxs = txs.filter(t => t.date.startsWith(today));

    const inflow = todayTxs.filter(t => t.type === TransactionType.INCOME || t.type === TransactionType.DEBT_PAYMENT)
      .reduce((acc, curr) => acc + curr.amount, 0);

    const outflow = todayTxs.filter(t => t.type === TransactionType.EXPENSE)
      .reduce((acc, curr) => acc + curr.amount, 0);

    const netDebt = txs.reduce((acc, curr) => {
      if (curr.type === TransactionType.DEBT) return acc + curr.amount;
      if (curr.type === TransactionType.DEBT_PAYMENT) return acc - curr.amount;
      return acc;
    }, 0);

    return { inflow, outflow, profit: inflow - outflow, debt: netDebt };
  }
};

