import React, { useState, useRef, useEffect } from 'react';
import { Sparkles, ArrowRight, X, Check, Loader2 } from 'lucide-react';
import { parseNaturalLanguage } from '../geminiService';
import { AIResponse, Transaction, TransactionType } from '../types';

interface CommandBarProps {
  onRecord: (tx: Omit<Transaction, "id" | "user_id">) => void;
  context: string;
}

export const CommandBar: React.FC<CommandBarProps> = ({ onRecord, context }) => {
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const [parsed, setParsed] = useState<AIResponse | null>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  const handleSubmit = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!input.trim() || loading) return;

    setLoading(true);
    try {
      const result = await parseNaturalLanguage(input, context);
      if (result.intent === 'RECORD' && result.transaction) {
        setParsed(result);
      } else if (result.intent === 'QUERY') {
        alert(result.query_answer || "I couldn't find an answer for that.");
        setInput("");
      } else {
        alert("Sorry, I didn't quite catch that. Try 'Sold item for 5000'");
      }
    } catch (err) {
      alert("Something went wrong with the AI assistant.");
    } finally {
      setLoading(false);
    }
  };

  const handleConfirm = () => {
    if (parsed?.transaction) {
      onRecord({
        ...parsed.transaction,
        date: new Date().toISOString()
      });
      setParsed(null);
      setInput("");
    }
  };

  const handleCancel = () => {
    setParsed(null);
  };

  return (
    <div className="fixed bottom-0 left-0 right-0 p-4 safe-pb z-50">
      <div className="max-w-md mx-auto relative">
        {parsed && (
          <div className="absolute bottom-full left-0 right-0 mb-4 animate-slide-up">
            <div className="bg-white border-2 border-indigo-500 rounded-3xl p-5 shadow-2xl">
              <p className="text-xs font-bold text-indigo-600 uppercase tracking-widest mb-1">Confirm Transaction</p>
              <div className="flex items-center justify-between mb-4">
                <div>
                  <h4 className="text-lg font-bold text-slate-800">{parsed.transaction?.description}</h4>
                  <p className="text-sm text-slate-500">{parsed.transaction?.category} • {parsed.transaction?.type}</p>
                </div>
                <div className="text-right">
                  <p className="text-xl font-extrabold text-indigo-600 underline">
                    {parsed.transaction?.amount}
                  </p>
                </div>
              </div>
              <div className="grid grid-cols-2 gap-3">
                <button 
                  onClick={handleCancel}
                  className="flex items-center justify-center space-x-2 py-3 bg-slate-100 text-slate-600 rounded-2xl font-bold active:scale-95 transition-all"
                >
                  <X className="w-5 h-5" />
                  <span>Cancel</span>
                </button>
                <button 
                  onClick={handleConfirm}
                  className="flex items-center justify-center space-x-2 py-3 bg-indigo-600 text-white rounded-2xl font-bold active:scale-95 transition-all shadow-lg shadow-indigo-200"
                >
                  <Check className="w-5 h-5" />
                  <span>Save Record</span>
                </button>
              </div>
            </div>
          </div>
        )}

        <form 
          onSubmit={handleSubmit}
          className={`flex items-center bg-indigo-600 rounded-full p-2 shadow-xl shadow-indigo-100 border border-white/20 ring-4 ring-indigo-500/10 transition-all duration-300 ${loading ? 'opacity-90' : 'opacity-100'}`}
        >
          <div className="flex-1 flex items-center px-4">
            {loading ? (
              <Loader2 className="w-5 h-5 text-white/50 animate-spin mr-3" />
            ) : (
              <Sparkles className="w-5 h-5 text-indigo-200 mr-3" />
            )}
            <input 
              ref={inputRef}
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder={loading ? "Analyzing..." : "Describe a sale or expense..."}
              className="w-full bg-transparent border-none focus:outline-none text-white placeholder-indigo-200 text-sm py-2"
              disabled={loading || !!parsed}
            />
          </div>
          <button 
            type="submit"
            disabled={loading || !input.trim() || !!parsed}
            className="w-10 h-10 bg-white rounded-full flex items-center justify-center text-indigo-600 active:scale-90 transition-all disabled:opacity-50"
          >
            <ArrowRight className="w-5 h-5" />
          </button>
        </form>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { db } from './db';
import { Transaction, Profile, TransactionType } from './types';
import { BentoGrid } from './components/BentoGrid';
import { HistoryList } from './components/HistoryList';
import { CommandBar } from './components/CommandBar';
import { Settings, BarChart3, LayoutDashboard, Search } from 'lucide-react';

const App: React.FC = () => {
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [profile, setProfile] = useState<Profile>(db.getProfile());
  const [stats, setStats] = useState(db.getStats());
  const [view, setView] = useState<'dashboard' | 'debts'>('dashboard');

  useEffect(() => {
    setTransactions(db.getTransactions());
    setStats(db.getStats());
  }, []);

  const handleNewRecord = (txData: Omit<Transaction, "id" | "user_id">) => {
    db.saveTransaction(txData);
    setTransactions(db.getTransactions());
    setStats(db.getStats());
  };

  const contextString = useMemo(() => {
    return `Business: ${profile.business_name}. Stats today: Inflow ${stats.inflow}, Outflow ${stats.outflow}. Net Debt: ${stats.debt}. Recent tx: ${transactions.slice(0, 3).map(t => t.description).join(", ")}.`;
  }, [profile, stats, transactions]);

  const filteredTransactions = useMemo(() => {
    if (view === 'debts') {
      return transactions.filter(t => t.type === TransactionType.DEBT || t.type === TransactionType.DEBT_PAYMENT);
    }
    return transactions;
  }, [transactions, view]);

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col max-w-md mx-auto shadow-2xl relative overflow-hidden ring-1 ring-slate-200">
      {/* Header */}
      <header className="glass sticky top-0 z-40 safe-pt border-b border-slate-200/50">
        <div className="px-6 py-4 flex items-center justify-between">
          <div>
            <h1 className="text-2xl font-extrabold text-indigo-600 tracking-tight">Kazi Ledger</h1>
            <p className="text-xs text-slate-500 font-bold uppercase tracking-widest">{profile.business_name}</p>
          </div>
          <button className="w-10 h-10 bg-slate-100 rounded-full flex items-center justify-center text-slate-600 active:scale-95 transition-all">
            <Settings className="w-5 h-5" />
          </button>
        </div>

        {/* Simple Tabs */}
        <div className="px-4 pb-2 flex space-x-2">
          <button 
            onClick={() => setView('dashboard')}
            className={`flex-1 flex items-center justify-center space-x-2 py-2 rounded-xl text-sm font-bold transition-all ${
              view === 'dashboard' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-100'
            }`}
          >
            <LayoutDashboard className="w-4 h-4" />
            <span>Dashboard</span>
          </button>
          <button 
            onClick={() => setView('debts')}
            className={`flex-1 flex items-center justify-center space-x-2 py-2 rounded-xl text-sm font-bold transition-all ${
              view === 'debts' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-100'
            }`}
          >
            <BarChart3 className="w-4 h-4" />
            <span>Debt Tracking</span>
          </button>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto pt-4">
        {view === 'dashboard' && (
          <>
            <BentoGrid stats={stats} currency={profile.currency} />
            <HistoryList transactions={filteredTransactions} currency={profile.currency} />
          </>
        )}

        {view === 'debts' && (
          <div className="animate-slide-up">
            <div className="p-4 bg-indigo-50 border-y border-indigo-100 mb-4 flex items-center justify-between">
              <div>
                <p className="text-indigo-600 text-xs font-bold uppercase">Outstanding Debt</p>
                <h3 className="text-2xl font-bold text-indigo-900">{profile.currency} {new Intl.NumberFormat().format(stats.debt)}</h3>
              </div>
              <div className="w-12 h-12 bg-white rounded-2xl flex items-center justify-center text-indigo-600 shadow-sm">
                <Search className="w-6 h-6" />
              </div>
            </div>
            <HistoryList transactions={filteredTransactions} currency={profile.currency} />
          </div>
        )}
      </main>

      {/* Floating AI Bar */}
      <CommandBar onRecord={handleNewRecord} context={contextString} />

      {/* Background decoration for modern feel */}
      <div className="fixed -top-24 -right-24 w-64 h-64 bg-indigo-400/5 rounded-full blur-3xl pointer-events-none -z-10"></div>
      <div className="fixed bottom-32 -left-24 w-64 h-64 bg-emerald-400/5 rounded-full blur-3xl pointer-events-none -z-10"></div>
    </div>
  );
};

export default App;

