import { GoogleGenAI, Type } from "@google/genai";
import { AIResponse, TransactionType } from "./types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

const responseSchema = {
  type: Type.OBJECT,
  properties: {
    intent: {
      type: Type.STRING,
      description: "RECORD for adding a transaction, QUERY for asking about history.",
    },
    transaction: {
      type: Type.OBJECT,
      properties: {
        type: { type: Type.STRING, description: "INCOME, EXPENSE, DEBT, or DEBT_PAYMENT" },
        amount: { type: Type.NUMBER },
        category: { type: Type.STRING },
        counterparty: { type: Type.STRING },
        description: { type: Type.STRING },
      },
    },
    query_answer: {
      type: Type.STRING,
      description: "The answer if the user is asking a question.",
    },
  },
  required: ["intent"],
};

export const parseNaturalLanguage = async (input: string, context: string): Promise<AIResponse> => {
  const prompt = `
    You are Kazi Ledger AI. Analyze this user input: "${input}".
    Context of existing ledger data summary: ${context}

    If it's a new record:
    - INCOME: "Sold 3 sodas for 5000" -> amount 5000, category "Sales", counterparty "Customer"
    - EXPENSE: "Paid 10000 for rent" -> amount 10000, category "Rent"
    - DEBT: "Gave John goods worth 2000 on credit" -> amount 2000, type DEBT, counterparty "John"
    - DEBT_PAYMENT: "John paid back 500" -> amount 500, type DEBT_PAYMENT, counterparty "John"

    If it's a query:
    - "How much did I make today?" -> answer based on context.

    Return the result in structured JSON.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
      },
    });

    return JSON.parse(response.text || "{}") as AIResponse;
  } catch (error) {
    console.error("AI Parsing Error:", error);
    throw error;
  }
};

export const analyzeReceipt = async (base64Image: string): Promise<AIResponse> => {
  const prompt = `
    Analyze this receipt or business document image.
    Extract the transaction details:
    - Determine if it is an EXPENSE (most receipts) or INCOME.
    - Extract the total amount.
    - Identify a suitable category (e.g., Supplies, Rent, Utilities, Inventory).
    - Identify the merchant or counterparty name.
    - Create a brief description.

    Return the result in structured JSON.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: [
        {
          inlineData: {
            mimeType: "image/jpeg",
            data: base64Image,
          },
        },
        { text: prompt },
      ],
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
      },
    });

    return JSON.parse(response.text || "{}") as AIResponse;
  } catch (error) {
    console.error("Vision Analysis Error:", error);
    throw error;
  }
};

export const generateInsights = async (context: string): Promise<string[]> => {
  const prompt = `
    Analyze this transaction data: "${context}"
    Provide 3 extremely short business insights. 
    EACH INSIGHT MUST BE EXACTLY 5 WORDS OR LESS.
    Example: "Sales up 10% today."
    Example: "John owes you 5,000."
    Example: "Reduce rent costs soon."

    Format your response as a JSON array of strings.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: { type: Type.STRING }
        }
      },
    });

    return JSON.parse(response.text || "[]") as string[];
  } catch (error) {
    return ["Track your daily sales.", "Debt tracking saves money.", "Monitor weekly totals."];
  }
};

import React from 'react';
import { TrendingUp, TrendingDown, Wallet, Users } from 'lucide-react';

interface BentoGridProps {
  stats: {
    inflow: number;
    outflow: number;
    profit: number;
    debt: number;
  };
  currency: string;
  timeframe: 'today' | 'weekly' | 'monthly';
}

export const BentoGrid: React.FC<BentoGridProps> = ({ stats, currency, timeframe }) => {
  const format = (val: number) => new Intl.NumberFormat().format(val);

  const label = timeframe === 'today' ? "Today's" : timeframe === 'weekly' ? "Weekly" : "Monthly";

  const renderStatCard = (
    title: string, 
    value: number, 
    bgColor: string, 
    borderColor: string, 
    icon: React.ReactNode, 
    textColor: string,
    valueColor: string,
    isIndigo: boolean = false
  ) => {
    const formattedValue = format(value);
    const valueLength = formattedValue.length + currency.length;
    // Dynamic font size based on length to prevent overflow
    const fontSize = valueLength > 12 ? 'text-lg' : valueLength > 8 ? 'text-xl' : 'text-2xl';

    return (
      <div className={`${bgColor} ${borderColor} p-4 rounded-3xl flex flex-col justify-between h-40 shadow-sm transition-transform active:scale-95 overflow-hidden`}>
        <div className={`${isIndigo ? 'bg-white/20' : 'bg-current opacity-10'} w-9 h-9 rounded-full flex items-center justify-center shrink-0`}>
          {icon}
        </div>
        <div className="mt-2">
          <p className={`${textColor} text-[10px] font-bold uppercase tracking-wider truncate`}>{title}</p>
          <h3 className={`${fontSize} font-black ${valueColor} leading-tight break-all`}>
            <span className="text-[10px] font-bold opacity-70 mr-0.5">{currency}</span>
            {formattedValue}
          </h3>
        </div>
      </div>
    );
  };

  return (
    <div className="grid grid-cols-2 gap-3 p-4 animate-slide-up">
      {renderStatCard(
        `${label} Inflow`, 
        stats.inflow, 
        "bg-emerald-50", 
        "border border-emerald-100", 
        <TrendingUp className="text-emerald-600 w-4 h-4" />, 
        "text-emerald-700", 
        "text-emerald-900"
      )}

      {renderStatCard(
        `${label} Outflow`, 
        stats.outflow, 
        "bg-rose-50", 
        "border border-rose-100", 
        <TrendingDown className="text-rose-600 w-4 h-4" />, 
        "text-rose-700", 
        "text-rose-900"
      )}

      {renderStatCard(
        `${label} Profit`, 
        stats.profit, 
        "bg-indigo-600", 
        "border-transparent", 
        <Wallet className="text-white w-4 h-4" />, 
        "text-indigo-100", 
        "text-white",
        true
      )}

      {renderStatCard(
        `Total Debt`, 
        stats.debt, 
        "bg-white", 
        "border border-slate-200", 
        <Users className="text-slate-600 w-4 h-4" />, 
        "text-slate-500", 
        "text-slate-900"
      )}
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { Sparkles, ArrowRight, X, Check, Loader2, ScanLine, Camera, RefreshCcw, Mic, MicOff } from 'lucide-react';
import { parseNaturalLanguage, analyzeReceipt } from '../geminiService';
import { AIResponse, Transaction } from '../types';

interface CommandBarProps {
  onRecord: (tx: Omit<Transaction, "id" | "user_id">) => void;
  context: string;
}

export const CommandBar: React.FC<CommandBarProps> = ({ onRecord, context }) => {
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const [parsed, setParsed] = useState<AIResponse | null>(null);
  const [isCameraOpen, setIsCameraOpen] = useState(false);
  const [cameraStream, setCameraStream] = useState<MediaStream | null>(null);
  const [isListening, setIsListening] = useState(false);

  const inputRef = useRef<HTMLInputElement>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const examples = [
    "Sold 3 sodas for 5000",
    "Paid rent 200k",
    "Lent 10k to Sam",
    "Bought inventory 50k",
    "Customer paid 15k debt",
    "Sold lunch for 8000"
  ];

  // Speech Recognition Logic
  const startListening = () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) {
      alert("Speech recognition is not supported in this browser.");
      return;
    }

    const recognition = new SpeechRecognition();
    recognition.lang = 'en-US';
    recognition.interimResults = false;
    recognition.maxAlternatives = 1;

    recognition.onstart = () => setIsListening(true);
    recognition.onend = () => setIsListening(false);
    recognition.onerror = () => setIsListening(false);

    recognition.onresult = (event: any) => {
      const transcript = event.results[0][0].transcript;
      setInput(transcript);
    };

    recognition.start();
  };

  const handleSubmit = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!input.trim() || loading) return;

    setLoading(true);
    try {
      const result = await parseNaturalLanguage(input, context);
      if (result.intent === 'RECORD' && result.transaction) {
        setParsed(result);
      } else if (result.intent === 'QUERY') {
        alert(result.query_answer || "I couldn't find an answer for that.");
        setInput("");
      } else {
        alert("Sorry, I didn't quite catch that. Try 'Sold item for 5000'");
      }
    } catch (err) {
      alert("Something went wrong with the AI assistant.");
    } finally {
      setLoading(false);
    }
  };

  const startCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'environment' },
        audio: false 
      });
      setCameraStream(stream);
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
      }
      setIsCameraOpen(true);
    } catch (err) {
      alert("Could not access camera. Please check your permissions.");
      console.error(err);
    }
  };

  const stopCamera = () => {
    if (cameraStream) {
      cameraStream.getTracks().forEach(track => track.stop());
      setCameraStream(null);
    }
    setIsCameraOpen(false);
  };

  const capturePhoto = async () => {
    if (!videoRef.current || !canvasRef.current) return;

    const video = videoRef.current;
    const canvas = canvasRef.current;
    const context = canvas.getContext('2d');

    if (context) {
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      context.drawImage(video, 0, 0, canvas.width, canvas.height);

      const base64 = canvas.toDataURL('image/jpeg').split(',')[1];
      stopCamera();
      setLoading(true);

      try {
        const result = await analyzeReceipt(base64);
        if (result.transaction) {
          setParsed(result);
        } else {
          alert("Could not find receipt details. Try typing the transaction.");
        }
      } catch (err) {
        alert("Error analyzing image.");
      } finally {
        setLoading(false);
      }
    }
  };

  const handleConfirm = () => {
    if (parsed?.transaction) {
      onRecord({
        ...parsed.transaction,
        date: new Date().toISOString()
      });
      setParsed(null);
      setInput("");
    }
  };

  const handleCancel = () => {
    setParsed(null);
  };

  return (
    <div className="fixed bottom-0 left-0 right-0 p-4 safe-pb z-50 pointer-events-none">
      <div className="max-w-md mx-auto relative pointer-events-auto">

        {/* Camera Modal Overlay */}
        {isCameraOpen && (
          <div className="fixed inset-0 bg-black z-[60] flex flex-col items-center justify-center p-6">
            <div className="relative w-full aspect-[3/4] rounded-3xl overflow-hidden border-2 border-white/20 shadow-2xl">
              <video 
                ref={videoRef} 
                autoPlay 
                playsInline 
                className="w-full h-full object-cover"
              />
              <div className="absolute inset-0 border-[40px] border-black/40 pointer-events-none">
                <div className="w-full h-full border-2 border-white/30 rounded-xl border-dashed"></div>
              </div>
              <div className="absolute top-4 left-0 right-0 text-center">
                <p className="text-white/80 text-[10px] font-bold uppercase tracking-widest">Align receipt inside frame</p>
              </div>
            </div>

            <div className="mt-12 flex items-center justify-between w-full px-8">
              <button 
                onClick={stopCamera}
                className="w-12 h-12 rounded-full bg-white/10 flex items-center justify-center text-white"
              >
                <X className="w-6 h-6" />
              </button>

              <button 
                onClick={capturePhoto}
                className="w-20 h-20 rounded-full border-4 border-white p-1 flex items-center justify-center active:scale-90 transition-all"
              >
                <div className="w-full h-full bg-white rounded-full"></div>
              </button>

              <button 
                className="w-12 h-12 rounded-full bg-white/10 flex items-center justify-center text-white opacity-40"
              >
                <RefreshCcw className="w-5 h-5" />
              </button>
            </div>
            <canvas ref={canvasRef} className="hidden" />
          </div>
        )}

        {/* Upper Action Layer: Snap & Ticker */}
        {!parsed && !loading && !isCameraOpen && (
          <div className="mb-3 space-y-3">
            <div className="overflow-hidden pointer-events-none opacity-40">
              <div className="animate-marquee">
                {[...examples, ...examples].map((ex, i) => (
                  <div 
                    key={i}
                    className="whitespace-nowrap text-indigo-500 text-[10px] font-bold px-4 py-1 flex items-center"
                  >
                    <span className="w-1.5 h-1.5 rounded-full bg-indigo-300 mr-2"></span>
                    {ex}
                  </div>
                ))}
              </div>
            </div>

            <div className="flex justify-center">
              <button
                type="button"
                onClick={startCamera}
                className="bg-white border-2 border-indigo-100 px-6 py-3 rounded-full flex items-center space-x-3 shadow-lg shadow-indigo-100/50 active:scale-95 transition-all animate-slide-up group"
              >
                <div className="bg-indigo-600 p-2 rounded-xl group-active:rotate-12 transition-transform">
                  <Camera className="w-5 h-5 text-white" />
                </div>
                <div className="text-left">
                  <span className="block text-sm font-extrabold text-indigo-600 leading-none">Snap Receipt</span>
                  <span className="text-[10px] text-indigo-400 font-bold uppercase tracking-tight">Auto-Extract Details</span>
                </div>
              </button>
            </div>
          </div>
        )}

        {parsed && (
          <div className="absolute bottom-full left-0 right-0 mb-4 animate-slide-up">
            <div className="bg-white border-2 border-indigo-500 rounded-3xl p-5 shadow-2xl">
              <div className="flex items-center space-x-2 mb-2">
                <div className="bg-emerald-100 p-1 rounded-md">
                   <Check className="w-3 h-3 text-emerald-600" />
                </div>
                <p className="text-xs font-bold text-indigo-600 uppercase tracking-widest">AI Extraction Complete</p>
              </div>
              <div className="flex items-center justify-between mb-4">
                <div>
                  <h4 className="text-lg font-bold text-slate-800">{parsed.transaction?.description}</h4>
                  <p className="text-sm text-slate-500">{parsed.transaction?.category} • {parsed.transaction?.type}</p>
                </div>
                <div className="text-right">
                  <p className="text-xl font-extrabold text-indigo-600 underline">
                    {parsed.transaction?.amount}
                  </p>
                </div>
              </div>
              <div className="grid grid-cols-2 gap-3">
                <button 
                  onClick={handleCancel}
                  className="flex items-center justify-center space-x-2 py-3 bg-slate-100 text-slate-600 rounded-2xl font-bold active:scale-95 transition-all"
                >
                  <X className="w-5 h-5" />
                  <span>Discard</span>
                </button>
                <button 
                  onClick={handleConfirm}
                  className="flex items-center justify-center space-x-2 py-3 bg-indigo-600 text-white rounded-2xl font-bold active:scale-95 transition-all shadow-lg shadow-indigo-200"
                >
                  <Check className="w-5 h-5" />
                  <span>Save Record</span>
                </button>
              </div>
            </div>
          </div>
        )}

        <form 
          onSubmit={handleSubmit}
          className={`flex items-center bg-indigo-600 rounded-full p-1.5 shadow-xl shadow-indigo-100 border border-white/20 ring-4 ring-indigo-500/10 transition-all duration-300 ${loading ? 'opacity-90' : 'opacity-100'}`}
        >
          <div className="flex-1 flex items-center px-4">
            {loading ? (
              <Loader2 className="w-5 h-5 text-white/50 animate-spin mr-3" />
            ) : isListening ? (
              <div className="w-5 h-5 flex items-center justify-center mr-3 relative">
                <div className="absolute inset-0 bg-red-400 rounded-full animate-ping opacity-50"></div>
                <Mic className="w-5 h-5 text-red-400 relative z-10" />
              </div>
            ) : (
              <Sparkles className="w-5 h-5 text-indigo-200 mr-3" />
            )}
            <input 
              ref={inputRef}
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder={isListening ? "Listening..." : loading ? "Analyzing..." : "Describe transaction..."}
              className="w-full bg-transparent border-none focus:outline-none text-white placeholder-indigo-200 text-sm py-2"
              disabled={loading || !!parsed || isCameraOpen}
            />
          </div>

          <div className="flex items-center space-x-1 pr-1">
            <button
              type="button"
              onClick={startListening}
              disabled={loading || !!parsed || isCameraOpen}
              className={`w-9 h-9 rounded-full flex items-center justify-center transition-all ${isListening ? 'bg-red-500 text-white' : 'bg-indigo-500 text-white hover:bg-indigo-400 active:scale-90'}`}
            >
