  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [timeframe, setTimeframe] = useState<'today' | 'weekly' | 'monthly'>('today');
  const [stats, setStats] = useState(db.getStats(currentAccount.id, timeframe));
  const [view, setView] = useState<'dashboard' | 'debts'>('dashboard');
  const [insights, setInsights] = useState<string[]>([]);
  const [loadingInsights, setLoadingInsights] = useState(false);

  const [isAccountMenuOpen, setIsAccountMenuOpen] = useState(false);
  const [isAddingAccount, setIsAddingAccount] = useState(false);
  const [newAccountName, setNewAccountName] = useState("");
  const [newAccountCurrency, setNewAccountCurrency] = useState("UGX");

  useEffect(() => {
    const txs = db.getTransactions(currentAccount.id);
    setTransactions(txs);
    setStats(db.getStats(currentAccount.id, timeframe));
  }, [currentAccount, timeframe]);

  useEffect(() => {
    const fetchInsights = async () => {
      if (transactions.length === 0) {
        setInsights([]);
        return;
      }
      setLoadingInsights(true);
      const context = `Business: ${currentAccount.name}. Currency: ${currentAccount.currency}. Timeframe: ${timeframe}. 
        Stats: Inflow ${stats.inflow}, Outflow ${stats.outflow}, Debt ${stats.debt}. 
        Sample Transactions: ${transactions.slice(0, 5).map(t => `${t.description} (${t.amount})`).join(', ')}`;

      const newInsights = await generateInsights(context);
      setInsights(newInsights);
      setLoadingInsights(false);
    };

    const timeoutId = setTimeout(fetchInsights, 500);
    return () => clearTimeout(timeoutId);
  }, [transactions.length, timeframe, currentAccount.id]);

  const handleNewRecord = (txData: Omit<Transaction, "id" | "user_id" | "account_id">) => {
    db.saveTransaction(txData, currentAccount.id);
    const updatedTxs = db.getTransactions(currentAccount.id);
    setTransactions(updatedTxs);
    setStats(db.getStats(currentAccount.id, timeframe));
  };

  const switchAccount = (account: BusinessAccount) => {
    setCurrentAccount(account);
    setProfile(prev => {
      const updated = { ...prev, active_account_id: account.id };
      db.updateProfile(updated);
      return updated;
    });
    setIsAccountMenuOpen(false);
  };

  const createNewAccount = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newAccountName.trim()) return;

    const newAcc = db.saveAccount({ name: newAccountName, currency: newAccountCurrency });
    setAccounts(db.getAccounts());
    switchAccount(newAcc);
    setIsAddingAccount(false);
    setNewAccountName("");
  };

  const contextString = useMemo(() => {
    return `Business: ${currentAccount.name}. Stats: Inflow ${stats.inflow}, Outflow ${stats.outflow}. Debt: ${stats.debt}. Recent tx: ${transactions.slice(0, 3).map(t => t.description).join(", ")}.`;
  }, [currentAccount, stats, transactions]);

  const filteredTransactions = useMemo(() => {
    let list = transactions;
    if (view === 'debts') {
      list = list.filter(t => t.type === TransactionType.DEBT || t.type === TransactionType.DEBT_PAYMENT);
    } else {
      const now = new Date();
      list = list.filter(t => {
        const d = new Date(t.date);
        if (timeframe === 'today') return d.toDateString() === now.toDateString();
        if (timeframe === 'weekly') return (now.getTime() - d.getTime()) <= 7 * 24 * 60 * 60 * 1000;
        if (timeframe === 'monthly') return d.getMonth() === now.getMonth() && d.getFullYear() === now.getFullYear();
        return true;
      });
    }
    return list;
  }, [transactions, view, timeframe]);

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col max-w-md mx-auto shadow-2xl relative overflow-hidden ring-1 ring-slate-200">
      {/* Header */}
      <header className="glass sticky top-0 z-40 safe-pt border-b border-slate-200/50">
        <div className="px-6 py-4 flex items-center justify-between">
          <div className="relative">
            <button 
              onClick={() => setIsAccountMenuOpen(!isAccountMenuOpen)}
              className="flex flex-col items-start group active:scale-95 transition-all"
            >
              <h1 className="text-xl font-extrabold text-indigo-600 tracking-tight flex items-center">
                {currentAccount.name}
                <ChevronDown className={`w-4 h-4 ml-1 transition-transform ${isAccountMenuOpen ? 'rotate-180' : ''}`} />
              </h1>
              <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Kazi Ledger • {currentAccount.currency}</p>
            </button>

            {/* Account Switcher Menu */}
            {isAccountMenuOpen && (
              <>
                <div className="fixed inset-0 z-10" onClick={() => setIsAccountMenuOpen(false)}></div>
                <div className="absolute top-full left-0 mt-2 w-64 bg-white rounded-3xl shadow-2xl border border-slate-100 z-20 py-3 animate-slide-up overflow-hidden">
                  <div className="px-4 py-2 mb-2 border-b border-slate-50">
                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Switch Business</p>
                  </div>
                  <div className="max-h-64 overflow-y-auto no-scrollbar">
                    {accounts.map((acc) => (
                      <button
                        key={acc.id}
                        onClick={() => switchAccount(acc)}
                        className={`w-full px-4 py-3 flex items-center space-x-3 transition-colors ${
                          currentAccount.id === acc.id ? 'bg-indigo-50 text-indigo-600' : 'hover:bg-slate-50 text-slate-700'
                        }`}
                      >
                        <Building2 className={`w-5 h-5 ${currentAccount.id === acc.id ? 'text-indigo-600' : 'text-slate-400'}`} />
                        <div className="text-left">
                          <p className="text-sm font-bold leading-none">{acc.name}</p>
                          <p className="text-[10px] opacity-70 mt-1">{acc.currency}</p>
                        </div>
                        {currentAccount.id === acc.id && <div className="ml-auto w-1.5 h-1.5 rounded-full bg-indigo-600"></div>}
                      </button>
                    ))}
                  </div>
                  <button 
                    onClick={() => { setIsAccountMenuOpen(false); setIsAddingAccount(true); }}
                    className="w-full px-4 py-4 flex items-center space-x-3 text-indigo-600 font-bold text-sm border-t border-slate-50 hover:bg-slate-50 transition-colors"
                  >
                    <div className="w-8 h-8 rounded-full bg-indigo-100 flex items-center justify-center">
                      <Plus className="w-4 h-4" />
                    </div>
                    <span>Add New Business</span>
                  </button>
                </div>
              </>
            )}
          </div>
          <button className="w-10 h-10 bg-slate-100 rounded-full flex items-center justify-center text-slate-600 active:scale-95 transition-all">
            <Settings className="w-5 h-5" />
          </button>
        </div>

        {/* Simple Tabs */}
        <div className="px-4 pb-2 flex space-x-2">
          <button 
            onClick={() => setView('dashboard')}
            className={`flex-1 flex items-center justify-center space-x-2 py-2 rounded-xl text-sm font-bold transition-all ${
              view === 'dashboard' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-100'
            }`}
          >
            <LayoutDashboard className="w-4 h-4" />
            <span>Dashboard</span>
          </button>
          <button 
            onClick={() => setView('debts')}
            className={`flex-1 flex items-center justify-center space-x-2 py-2 rounded-xl text-sm font-bold transition-all ${
              view === 'debts' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-100'
            }`}
          >
            <BarChart3 className="w-4 h-4" />
            <span>Debt Tracking</span>
          </button>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto pt-4">
        {view === 'dashboard' && (
          <>
            {/* Timeframe Selector */}
            <div className="px-4 mb-2 flex items-center justify-between">
              <div className="flex bg-slate-100 p-1 rounded-xl w-full">
                {(['today', 'weekly', 'monthly'] as const).map((t) => (
                  <button
                    key={t}
                    onClick={() => setTimeframe(t)}
                    className={`flex-1 py-2 text-[10px] font-extrabold uppercase tracking-widest rounded-lg transition-all ${
                      timeframe === t ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400'
                    }`}
                  >
                    {t}
                  </button>
                ))}
              </div>
            </div>

            <BentoGrid stats={stats} currency={currentAccount.currency} timeframe={timeframe} />

            {/* AI Insights Section */}
            <AIInsights insights={insights} loading={loadingInsights} />

            <HistoryList transactions={filteredTransactions} currency={currentAccount.currency} />
          </>
        )}

        {view === 'debts' && (
          <div className="animate-slide-up">
            <div className="p-4 bg-indigo-50 border-y border-indigo-100 mb-4 flex items-center justify-between">
              <div>
                <p className="text-indigo-600 text-xs font-bold uppercase">Outstanding Debt</p>
                <h3 className="text-2xl font-bold text-indigo-900">{currentAccount.currency} {new Intl.NumberFormat().format(stats.debt)}</h3>
              </div>
              <div className="w-12 h-12 bg-white rounded-2xl flex items-center justify-center text-indigo-600 shadow-sm">
                <Search className="w-6 h-6" />
              </div>
            </div>
            <HistoryList transactions={filteredTransactions} currency={currentAccount.currency} />
          </div>
        )}
      </main>

      {/* Account Creation Modal */}
      {isAddingAccount && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 glass">
          <div className="w-full bg-white rounded-[40px] shadow-2xl border border-indigo-100 p-8 animate-slide-up relative overflow-hidden">
            <button 
              onClick={() => setIsAddingAccount(false)}
              className="absolute top-6 right-6 w-10 h-10 bg-slate-100 rounded-full flex items-center justify-center text-slate-500 active:scale-95 transition-all"
            >
              <X className="w-5 h-5" />
            </button>
            <div className="mb-8">
              <div className="w-16 h-16 bg-indigo-600 rounded-3xl flex items-center justify-center text-white shadow-xl shadow-indigo-200 mb-6">
                <Plus className="w-8 h-8" />
              </div>
              <h2 className="text-2xl font-black text-slate-800 tracking-tight leading-none mb-2">New Business</h2>
              <p className="text-sm text-slate-500 font-medium">Create a separate ledger for your other business.</p>
            </div>
            <form onSubmit={createNewAccount} className="space-y-6">
              <div>
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block mb-2 px-1">Business Name</label>
                <input 
                  autoFocus
                  type="text" 
                  value={newAccountName}
                  onChange={(e) => setNewAccountName(e.target.value)}
                  placeholder="e.g. Fish Business, Petro Station"
                  className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-600 focus:outline-none transition-all font-bold text-slate-800"
                />
              </div>
              <div>
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block mb-2 px-1">Currency</label>
                <select 
                  value={newAccountCurrency}
                  onChange={(e) => setNewAccountCurrency(e.target.value)}
                  className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-600 focus:outline-none transition-all font-bold text-slate-800 appearance-none"
                >
                  <option value="UGX">Ugandan Shilling (UGX)</option>
                  <option value="KES">Kenyan Shilling (KES)</option>
                  <option value="USD">US Dollar (USD)</option>
                  <option value="TZS">Tanzanian Shilling (TZS)</option>
                </select>
              </div>
              <button 
                type="submit"
                className="w-full py-5 bg-indigo-600 text-white rounded-3xl font-black text-lg shadow-xl shadow-indigo-200 active:scale-95 transition-all mt-4"
              >
                Create Ledger
              </button>
            </form>
          </div>
        </div>
      )}

      {/* Floating AI Bar */}
      <CommandBar onRecord={handleNewRecord} context={contextString} />

      {/* Background decoration */}
      <div className="fixed -top-24 -right-24 w-64 h-64 bg-indigo-400/5 rounded-full blur-3xl pointer-events-none -z-10"></div>
      <div className="fixed bottom-32 -left-24 w-64 h-64 bg-emerald-400/5 rounded-full blur-3xl pointer-events-none -z-10"></div>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { Sparkles, ArrowRight, X, Check, Loader2, ScanLine, Camera, RefreshCcw, Mic, MicOff } from 'lucide-react';
import { parseNaturalLanguage, analyzeReceipt } from '../geminiService';
import { AIResponse, Transaction } from '../types';

interface CommandBarProps {
  onRecord: (tx: Omit<Transaction, "id" | "user_id">) => void;
  context: string;
}

export const CommandBar: React.FC<CommandBarProps> = ({ onRecord, context }) => {
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const [parsed, setParsed] = useState<AIResponse | null>(null);
  const [isCameraOpen, setIsCameraOpen] = useState(false);
  const [cameraStream, setCameraStream] = useState<MediaStream | null>(null);
  const [isListening, setIsListening] = useState(false);
  const [exampleIndex, setExampleIndex] = useState(0);

  const inputRef = useRef<HTMLInputElement>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const examples = [
    "Sold 3 fish for 5000",
    "Paid rent 200k",
    "Lent 10k to Sam",
    "Bought chicken feed 50k",
    "Customer paid 15k debt",
    "Sold lunch for 8000",
    "Paid electricity bill 40k"
  ];

  useEffect(() => {
    const interval = setInterval(() => {
      setExampleIndex((prev) => (prev + 1) % examples.length);
    }, 4000);
    return () => clearInterval(interval);
  }, []);

  const startListening = () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) {
      alert("Speech recognition is not supported in this browser.");
      return;
    }

    const recognition = new SpeechRecognition();
    recognition.lang = 'en-US';
    recognition.interimResults = false;
    recognition.maxAlternatives = 1;

    recognition.onstart = () => setIsListening(true);
    recognition.onend = () => setIsListening(false);
    recognition.onerror = () => setIsListening(false);

    recognition.onresult = (event: any) => {
      const transcript = event.results[0][0].transcript;
      setInput(transcript);
    };

    recognition.start();
  };

  const handleSubmit = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!input.trim() || loading) return;

    setLoading(true);
    try {
      const result = await parseNaturalLanguage(input, context);
      if (result.intent === 'RECORD' && result.transaction) {
        setParsed(result);
      } else if (result.intent === 'QUERY') {
        alert(result.query_answer || "I couldn't find an answer for that.");
        setInput("");
      } else {
        alert("Sorry, I didn't catch that. Try 'Sold item for 5000'");
      }
    } catch (err) {
      alert("Something went wrong with the AI assistant.");
    } finally {
      setLoading(false);
    }
  };

  const startCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'environment', width: { ideal: 1280 }, height: { ideal: 720 } },
        audio: false 
      });
      setCameraStream(stream);
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
      }
      setIsCameraOpen(true);
    } catch (err) {
      alert("Could not access camera. Check permissions.");
      console.error(err);
    }
  };

  const stopCamera = () => {
    if (cameraStream) {
      cameraStream.getTracks().forEach(track => track.stop());
      setCameraStream(null);
    }
    setIsCameraOpen(false);
  };

  const capturePhoto = async () => {
    if (!videoRef.current || !canvasRef.current) return;

    const video = videoRef.current;
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');

    if (ctx) {
      const MAX_WIDTH = 1024;
      const scale = Math.min(1, MAX_WIDTH / video.videoWidth);
      canvas.width = video.videoWidth * scale;
      canvas.height = video.videoHeight * scale;

      ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
      const base64 = canvas.toDataURL('image/jpeg', 0.75).split(',')[1];

      stopCamera();
      setLoading(true);

      try {
        const result = await analyzeReceipt(base64);
        if (result.transaction) {
          setParsed(result);
        } else {
          alert("Couldn't read receipt. Try typing details.");
        }
      } catch (err) {
        alert("Error analyzing image.");
      } finally {
        setLoading(false);
      }
    }
  };

  const handleConfirm = () => {
    if (parsed?.transaction) {
      onRecord({
        ...parsed.transaction,
        date: new Date().toISOString()
      });
      setParsed(null);
      setInput("");
    }
  };

  const handleCancel = () => {
    setParsed(null);
  };

  return (
    <div className="fixed bottom-0 left-0 right-0 p-4 safe-pb z-50 pointer-events-none">
      <div className="max-w-md mx-auto relative pointer-events-auto">

        {/* Camera Modal Overlay */}
        {isCameraOpen && (
          <div className="fixed inset-0 bg-black z-[60] flex flex-col items-center justify-center p-6">
            <div className="relative w-full aspect-[3/4] rounded-3xl overflow-hidden border-2 border-white/20 shadow-2xl">
              <video 
                ref={videoRef} 
                autoPlay 
                playsInline 
                className="w-full h-full object-cover"
              />
              <div className="absolute inset-0 border-[40px] border-black/40 pointer-events-none">
                <div className="w-full h-full border-2 border-white/30 rounded-xl border-dashed"></div>
              </div>
              <div className="absolute top-4 left-0 right-0 text-center">
                <p className="text-white/80 text-[10px] font-bold uppercase tracking-widest">Align receipt inside frame</p>
              </div>
            </div>

            <div className="mt-12 flex items-center justify-between w-full px-8">
              <button onClick={stopCamera} className="w-12 h-12 rounded-full bg-white/10 flex items-center justify-center text-white">
                <X className="w-6 h-6" />
              </button>
              <button onClick={capturePhoto} className="w-20 h-20 rounded-full border-4 border-white p-1 flex items-center justify-center active:scale-90 transition-all">
                <div className="w-full h-full bg-white rounded-full"></div>
              </button>
              <div className="w-12 h-12"></div>
            </div>
            <canvas ref={canvasRef} className="hidden" />
          </div>
        )}

        {/* Upper Action Layer: Snap */}
        {!parsed && !loading && !isCameraOpen && (
          <div className="mb-2 flex justify-center animate-slide-up">
            <button
              type="button"
              onClick={startCamera}
              className="bg-white border-2 border-indigo-100 px-5 py-2.5 rounded-full flex items-center space-x-3 shadow-lg shadow-indigo-100/50 active:scale-95 transition-all group"
            >
              <div className="bg-indigo-600 p-1.5 rounded-lg group-active:rotate-12 transition-transform">
                <Camera className="w-4 h-4 text-white" />
              </div>
              <div className="text-left">
                <span className="block text-xs font-extrabold text-indigo-600 leading-none">Snap Receipt</span>
              </div>
            </button>
          </div>
        )}

        {/* The Auto-Scrolling Hint - Directly above the bar */}
        {!parsed && !loading && !isCameraOpen && (
          <div className="h-6 flex items-center justify-center mb-1 overflow-hidden">
            <p key={exampleIndex} className="text-[10px] font-bold text-indigo-400 uppercase tracking-widest animate-hint flex items-center">
              <Sparkles className="w-3 h-3 mr-1 text-indigo-300" />
              Try: "{examples[exampleIndex]}"
            </p>
          </div>
        )}

        {parsed && (
          <div className="absolute bottom-full left-0 right-0 mb-4 animate-slide-up">
            <div className="bg-white border-2 border-indigo-500 rounded-3xl p-5 shadow-2xl">
              <div className="flex items-center space-x-2 mb-2">
                <div className="bg-emerald-100 p-1 rounded-md">
                   <Check className="w-3 h-3 text-emerald-600" />
                </div>
                <p className="text-xs font-bold text-indigo-600 uppercase tracking-widest">Extracted Instantly</p>
              </div>
              <div className="flex items-center justify-between mb-4">
                <div>
                  <h4 className="text-lg font-bold text-slate-800">{parsed.transaction?.description}</h4>
                  <p className="text-sm text-slate-500">{parsed.transaction?.category} • {parsed.transaction?.type}</p>
                </div>
                <div className="text-right">
                  <p className="text-xl font-extrabold text-indigo-600 underline">
                    {parsed.transaction?.amount}
                  </p>
                </div>
              </div>
              <div className="grid grid-cols-2 gap-3">
                <button onClick={handleCancel} className="flex items-center justify-center space-x-2 py-3 bg-slate-100 text-slate-600 rounded-2xl font-bold active:scale-95 transition-all">
                  <X className="w-5 h-5" />
                  <span>Discard</span>
                </button>
                <button onClick={handleConfirm} className="flex items-center justify-center space-x-2 py-3 bg-indigo-600 text-white rounded-2xl font-bold active:scale-95 transition-all shadow-lg shadow-indigo-200">
                  <Check className="w-5 h-5" />
                  <span>Confirm</span>
                </button>
              </div>
            </div>
          </div>
        )}

        <form 
          onSubmit={handleSubmit}
          className={`flex items-center bg-indigo-600 rounded-full p-1.5 shadow-xl shadow-indigo-100 border border-white/20 ring-4 ring-indigo-500/10 transition-all duration-300 ${loading ? 'opacity-90' : 'opacity-100'}`}
        >
          <div className="flex-1 flex items-center px-4">
            {loading ? (
              <div className="flex items-center mr-3">
                <Loader2 className="w-5 h-5 text-white animate-spin" />
              </div>
            ) : isListening ? (
              <div className="w-5 h-5 flex items-center justify-center mr-3 relative">
                <div className="absolute inset-0 bg-red-400 rounded-full animate-ping opacity-50"></div>
                <Mic className="w-5 h-5 text-red-400 relative z-10" />
              </div>
            ) : (
              <Sparkles className="w-5 h-5 text-indigo-200 mr-3" />
            )}
            <input 
              ref={inputRef}
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder={isListening ? "Listening..." : loading ? "Extracting..." : "Describe transaction..."}
              className="w-full bg-transparent border-none focus:outline-none text-white placeholder-indigo-200 text-sm py-2"
              disabled={loading || !!parsed || isCameraOpen}
            />
          </div>

          <div className="flex items-center space-x-1 pr-1">
            <button
              type="button"
              onClick={startListening}
              disabled={loading || !!parsed || isCameraOpen}
              className={`w-9 h-9 rounded-full flex items-center justify-center transition-all ${isListening ? 'bg-red-500 text-white shadow-inner shadow-red-700/50' : 'bg-indigo-50 text-white/50 hover:bg-indigo-400 active:scale-90'}`}
            >
              <Mic className="w-5 h-5" />
            </button>
            <button 
              type="submit"
              disabled={loading || !input.trim() || !!parsed || isCameraOpen}
              className="w-9 h-9 bg-white rounded-full flex items-center justify-center text-indigo-600 active:scale-90 transition-all disabled:opacity-50 shadow-sm"
            >
              <ArrowRight className="w-5 h-5" />
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { Sparkles, ArrowRight, X, Check, Loader2, ScanLine, Camera, RefreshCcw, Mic, MicOff } from 'lucide-react';
import { parseNaturalLanguage, analyzeReceipt } from '../geminiService';
import { AIResponse, Transaction } from '../types';

interface CommandBarProps {
  // Fix: Omit account_id from the record payload as it's handled by the parent component/database
  onRecord: (tx: Omit<Transaction, "id" | "user_id" | "account_id">) => void;
  context: string;
}

export const CommandBar: React.FC<CommandBarProps> = ({ onRecord, context }) => {
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
