        if (timeframe === 'monthly') return d.getMonth() === now.getMonth() && d.getFullYear() === now.getFullYear();
        return true;
      });
    }
    return list;
  }, [transactions, view, timeframe]);

  if (!hasStarted) {
    return <LandingPage onStart={handleStart} />;
  }

