          >
            <BarChart3 className="w-4 h-4" />
            <span>Debt Tracking</span>
          </button>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto pt-4 no-scrollbar">
        {view === 'dashboard' && (
