import { createClient } from '@supabase/supabase-js';

// Accessing environment variables for Supabase configuration.
// We use a type cast to 'any' to avoid TS errors in environments where process.env is not fully typed.
const supabaseUrl = (process.env as any).SUPABASE_URL;
const supabaseAnonKey = (process.env as any).SUPABASE_ANON_KEY;

if (!supabaseUrl || !supabaseAnonKey) {
  console.error(
    "Kazi Ledger Configuration Error: SUPABASE_URL or SUPABASE_ANON_KEY is missing. " +
    "Please ensure these environment variables are set in your deployment platform. " +
    "Authentication features will be disabled until valid credentials are provided."
  );
}

/**
 * Initialize the Supabase client.
 * We provide fallback strings to prevent createClient from throwing a fatal "required" error.
 * This ensures the app can still boot, show the landing page, and explain why it needs setup.
 */
export const supabase = createClient(
  supabaseUrl || 'https://placeholder-please-set-env-vars.supabase.co',
  supabaseAnonKey || 'placeholder-anon-key'
);

